vedor)", "fase": "Semana 2", "etapa": "Personalização Estrutural", "tarefa": "Ajuste estrutural da Página de Produto", "comoExecutar": "https://docs.google.com/document/d/1m4Z8LG00V43SKjeO0e4MJQkz_fv4pRj0qDlyeon134s/edit?tab=t.hbbll2vrgtel", "estimativaHoras": "3"}, {"dri": "Profissional de Web Design (Desenvolvedor)", "fase": "Semana 2", "etapa": "Personalização Estrutural", "tarefa": "Ajuste estrutural da Página de Categoria", "comoExecutar": "https://docs.google.com/document/d/1m4Z8LG00V43SKjeO0e4MJQkz_fv4pRj0qDlyeon134s/edit?tab=t.hbbll2vrgtel", "estimativaHoras": "2"}, {"dri": "Profissional de Web Design (Desenvolvedor)", "fase": "Semana 2", "etapa": "Personalização Estrutural", "tarefa": "Customização parcial do Checkout (visual permitido)", "comoExecutar": "https://docs.google.com/document/d/1m4Z8LG00V43SKjeO0e4MJQkz_fv4pRj0qDlyeon134s/edit?tab=t.hbbll2vrgtel", "estimativaHoras": "2"}, {"dri": "Profissional de Web Design (Desenvolvedor)", "fase": "Semana 2", "etapa": "Integração com ERP", "tarefa": "Configuração e Integração do ERP (Bling)", "comoExecutar": "https://docs.google.com/document/d/1m4Z8LG00V43SKjeO0e4MJQkz_fv4pRj0qDlyeon134s/edit?tab=t.hbbll2vrgtel", "estimativaHoras": "4"}, {"dri": "Profissional de Web Design (Desenvolvedor)", "fase": "Semana 2", "etapa": "Integração com ERP", "tarefa": "Inserção do token no painel da loja", "comoExecutar": "https://docs.google.com/document/d/1m4Z8LG00V43SKjeO0e4MJQkz_fv4pRj0qDlyeon134s/edit?tab=t.hbbll2vrgtel", "estimativaHoras": "1"}, {"dri": "Profissional de Web Design (Desenvolvedor)", "fase": "Semana 2", "etapa": "Integração com ERP", "tarefa": "Mapeamento de categorias, NCMs e referências", "comoExecutar": "https://docs.google.com/document/d/1m4Z8LG00V43SKjeO0e4MJQkz_fv4pRj0qDlyeon134s/edit?tab=t.hbbll2vrgtel", "estimativaHoras": "2"}, {"dri": "Profissional de Web Design (Desenvolvedor)", "fase": "Semana 2", "etapa": "Gateway de Pagamento", "tarefa": "Configuração de Gateway", "comoExecutar": "https://docs.